"use client";

import { useFieldArray, useForm } from "react-hook-form";
import CategoryForm from "../ui/form/categoryForm";
import type { Category, MenuForm as MenuFormType } from "@/data/types/dishMenu";
import { useRouter, useParams } from "next/navigation";
import { Button } from "@radix-ui/themes";
import { saveMenuToFirestore } from "@/lib/firebase/restantMenu";
import { useFirmId } from "@/lib/firebase/restaurants";
import { doc, getDoc } from "firebase/firestore";
import { db } from "@/lib/firebase/client";
import { useEffect } from "react";
import { MenuEditorEmpty } from "../ui/form/menuEditor/MenuEditorEmpty";

const MenuForm = () => {
    const { firmId, loading } = useFirmId();
    console.log("MenuCategoryForm state", { loading, firmId });

    const router = useRouter();
    const params = useParams<{ id: string }>();
    const restaurantId = params?.id;
    const form = useForm<MenuFormType>({
        mode: "onSubmit",
        defaultValues: {
            categories: [
                {
                    id: crypto.randomUUID(),
                    name: "",
                    dishes: [],
                },
            ],
        },
    });

    const { control, handleSubmit } = form;

    const { fields, append, remove } = useFieldArray({
        name: "categories",
        control,
    });

    const onAddNewCategory = () => {
        const category: Category = {
            id: crypto.randomUUID(),
            name: "",
            dishes: [],
        };
        append(category);
    };

    const onHandleSubmit = async (data: MenuFormType) => {
        try {
            if (!firmId) return;
            await saveMenuToFirestore(firmId, params.id, data);
            router.push(`/restaurant/${params.id}`);
        } catch (error) {
            console.error("Error saving menu:", error);
        }
    };
    useEffect(() => {
        if (!firmId || !restaurantId) return;

        const loadMenu = async () => {
            const ref = doc(
                db,
                "firms",
                firmId,
                "restaurants",
                restaurantId,
                "menu",
                "main"
            );

            const snap = await getDoc(ref);

            if (snap.exists()) {
                form.reset({
                    categories: snap.data().categories || [],
                });
            }
        };

        loadMenu();
    }, [firmId, restaurantId]);


    if (loading) {
        return <div>Ładowanie danych firmy…</div>;
    }

    if (!firmId) {
        return <div>Brak przypisanej firmy do użytkownika</div>;
    }

    return (

        <form onSubmit={handleSubmit(onHandleSubmit)}>
            <div className="p-2">

                <div>

                    {fields.length === 0 ?
                        <div> <MenuEditorEmpty />
                            <Button type="button" color="blue" onClick={onAddNewCategory}>
                                Dodaj kategorię
                            </Button>
                        </div>

                        : fields.map((category, indexCategory) => (
                            <div key={category.id}>
                                <CategoryForm
                                    form={form}
                                    index={indexCategory}
                                    category={category as Category}
                                    onRemoveCategory={() => remove(indexCategory)}
                                />
                            </div>
                        ))}
                </div>

                <div className="flex gap-2 p-2">
                    <Button type="submit" className="mt-6 bg-green-600 text-white">
                        Zapisz menu
                    </Button>

                    <Button
                        type="button"
                        onClick={() => router.push(`/owner/restaurants/${params.id}`)}
                        className="mt-6 bg-green-600 text-white"
                    >
                        Powrót do restauracji
                    </Button>

                    <Button type="button" color="blue" onClick={onAddNewCategory}>
                        Dodaj kategorię
                    </Button>
                </div>
            </div>
        </form>
    );
};

export default MenuForm;
